import requests
import json
import urllib.parse
from dataclasses import dataclass, field
from typing import Optional


@dataclass
class RabbitMQPermission:
    """Represents RabbitMQ permissions for a user on a vhost."""
    configure: str = ".*"  # regex for resources user can configure
    write: str = ".*"      # regex for resources user can write to
    read: str = ".*"       # regex for resources user can read from


@dataclass
class RabbitMQUser:
    """Represents a RabbitMQ user."""
    username: str
    password: str
    tags: str = ""  # comma-separated: management, monitoring, policymaker, administrator


@dataclass
class RabbitMQVhost:
    """Represents a RabbitMQ virtual host configuration."""
    name: str
    description: str = ""
    tracing: bool = False
    users: list = field(default_factory=list)  # list of (RabbitMQUser, RabbitMQPermission) tuples


class RabbitMQConfigurator:
    """Configures RabbitMQ virtual hosts and permissions via the Management HTTP API."""

    def __init__(
        self,
        host: str = "localhost",
        port: int = 15672,
        admin_user: str = "guest",
        admin_password: str = "guest",
        use_https: bool = False,
        verify_ssl: bool = True,
    ):
        protocol = "https" if use_https else "http"
        self.base_url = f"{protocol}://{host}:{port}/api"
        self.auth = (admin_user, admin_password)
        self.verify_ssl = verify_ssl
        self.session = requests.Session()
        self.session.auth = self.auth
        self.session.headers.update({"Content-Type": "application/json"})
        self.session.verify = self.verify_ssl

    def _encode_vhost(self, vhost_name: str) -> str:
        """URL-encode the vhost name (/ becomes %2F)."""
        return urllib.parse.quote(vhost_name, safe="")

    def _request(self, method: str, endpoint: str, data: Optional[dict] = None) -> requests.Response:
        """Make an HTTP request to the RabbitMQ Management API."""
        url = f"{self.base_url}/{endpoint}"
        kwargs = {}
        if data is not None:
            kwargs["data"] = json.dumps(data)

        response = self.session.request(method, url, **kwargs)
        return response

    def check_connection(self) -> bool:
        """Verify connectivity to the RabbitMQ Management API."""
        try:
            response = self._request("GET", "overview")
            if response.status_code == 200:
                info = response.json()
                print(f"Connected to RabbitMQ {info.get('rabbitmq_version', 'unknown')} "
                      f"on cluster '{info.get('cluster_name', 'unknown')}'")
                return True
            else:
                print(f"Failed to connect: HTTP {response.status_code} - {response.text}")
                return False
        except requests.ConnectionError as e:
            print(f"Connection error: {e}")
            return False

    def list_vhosts(self) -> list:
        """List all existing virtual hosts."""
        response = self._request("GET", "vhosts")
        if response.status_code == 200:
            return response.json()
        print(f"Failed to list vhosts: {response.status_code} - {response.text}")
        return []

    def get_vhost(self, vhost_name: str) -> Optional[dict]:
        """Get details of a specific virtual host."""
        encoded = self._encode_vhost(vhost_name)
        response = self._request("GET", f"vhosts/{encoded}")
        if response.status_code == 200:
            return response.json()
        return None

    def create_vhost(self, vhost_name: str, description: str = "", tracing: bool = False) -> bool:
        """Create a new virtual host."""
        encoded = self._encode_vhost(vhost_name)
        data = {
            "description": description,
            "tracing": tracing,
        }
        response = self._request("PUT", f"vhosts/{encoded}", data=data)
        if response.status_code in (201, 204):
            print(f"  [OK] Virtual host '{vhost_name}' created successfully")
            return True
        elif response.status_code == 204:
            print(f"  [OK] Virtual host '{vhost_name}' already exists (updated)")
            return True
        else:
            print(f"  [FAIL] Failed to create vhost '{vhost_name}': "
                  f"{response.status_code} - {response.text}")
            return False

    def delete_vhost(self, vhost_name: str) -> bool:
        """Delete a virtual host."""
        encoded = self._encode_vhost(vhost_name)
        response = self._request("DELETE", f"vhosts/{encoded}")
        if response.status_code == 204:
            print(f"  [OK] Virtual host '{vhost_name}' deleted successfully")
            return True
        else:
            print(f"  [FAIL] Failed to delete vhost '{vhost_name}': "
                  f"{response.status_code} - {response.text}")
            return False

    def list_users(self) -> list:
        """List all existing users."""
        response = self._request("GET", "users")
        if response.status_code == 200:
            return response.json()
        print(f"Failed to list users: {response.status_code} - {response.text}")
        return []

    def get_user(self, username: str) -> Optional[dict]:
        """Get details of a specific user."""
        encoded = urllib.parse.quote(username, safe="")
        response = self._request("GET", f"users/{encoded}")
        if response.status_code == 200:
            return response.json()
        return None

    def create_user(self, username: str, password: str, tags: str = "") -> bool:
        """Create a new user or update an existing one."""
        encoded = urllib.parse.quote(username, safe="")
        data = {
            "password": password,
            "tags": tags,
        }
        response = self._request("PUT", f"users/{encoded}", data=data)
        if response.status_code in (201, 204):
            print(f"  [OK] User '{username}' created/updated successfully (tags: '{tags}')")
            return True
        else:
            print(f"  [FAIL] Failed to create user '{username}': "
                  f"{response.status_code} - {response.text}")
            return False

    def delete_user(self, username: str) -> bool:
        """Delete a user."""
        encoded = urllib.parse.quote(username, safe="")
        response = self._request("DELETE", f"users/{encoded}")
        if response.status_code == 204:
            print(f"  [OK] User '{username}' deleted successfully")
            return True
        else:
            print(f"  [FAIL] Failed to delete user '{username}': "
                  f"{response.status_code} - {response.text}")
            return False

    def set_permissions(
        self,
        vhost_name: str,
        username: str,
        permission: RabbitMQPermission,
    ) -> bool:
        """Set permissions for a user on a virtual host."""
        encoded_vhost = self._encode_vhost(vhost_name)
        encoded_user = urllib.parse.quote(username, safe="")
        data = {
            "configure": permission.configure,
            "write": permission.write,
            "read": permission.read,
        }
        response = self._request(
            "PUT",
            f"permissions/{encoded_vhost}/{encoded_user}",
            data=data,
        )
        if response.status_code in (201, 204):
            print(f"  [OK] Permissions set for '{username}' on vhost '{vhost_name}' "
                  f"(configure='{permission.configure}', write='{permission.write}', "
                  f"read='{permission.read}')")
            return True
        else:
            print(f"  [FAIL] Failed to set permissions for '{username}' on '{vhost_name}': "
                  f"{response.status_code} - {response.text}")
            return False

    def get_permissions(self, vhost_name: str, username: str) -> Optional[dict]:
        """Get permissions for a user on a virtual host."""
        encoded_vhost = self._encode_vhost(vhost_name)
        encoded_user = urllib.parse.quote(username, safe="")
        response = self._request("GET", f"permissions/{encoded_vhost}/{encoded_user}")
        if response.status_code == 200:
            return response.json()
        return None

    def list_permissions_for_vhost(self, vhost_name: str) -> list:
        """List all permissions on a virtual host."""
        encoded_vhost = self._encode_vhost(vhost_name)
        response = self._request("GET", f"vhosts/{encoded_vhost}/permissions")
        if response.status_code == 200:
            return response.json()
        return []

    def set_topic_permissions(
        self,
        vhost_name: str,
        username: str,
        exchange: str = "amq.topic",
        write: str = ".*",
        read: str = ".*",
    ) -> bool:
        """Set topic permissions for a user on a virtual host."""
        encoded_vhost = self._encode_vhost(vhost_name)
