    def create_exchange(
        self,
        vhost_name: str,
        exchange_name: str,
        exchange_type: str = "topic",
        durable: bool = True,
        auto_delete: bool = False,
        internal: bool = False,
        arguments: Optional[dict] = None,
    ) -> bool:
        """Create an exchange on a virtual host."""
        encoded_vhost = self._encode_vhost(vhost_name)
        encoded_exchange = urllib.parse.quote(exchange_name, safe="")
        data = {
            "type": exchange_type,
            "durable": durable,
            "auto_delete": auto_delete,
            "internal": internal,
            "arguments": arguments or {},
        }
        response = self._request(
            "PUT",
            f"exchanges/{encoded_vhost}/{encoded_exchange}",
            data=data,
        )
        if response.status_code in (201, 204):
            print(f"  [OK] Exchange '{exchange_name}' created on vhost '{vhost_name}' "
                  f"(type: {exchange_type})")
            return True
        else:
            print(f"  [FAIL] Failed to create exchange: "
                  f"{response.status_code} - {response.text}")
            return False

    def create_queue(
        self,
        vhost_name: str,
        queue_name: str,
        durable: bool = True,
        auto_delete: bool = False,
        arguments: Optional[dict] = None,
    ) -> bool:
        """Create a queue on a virtual host."""
        encoded_vhost = self._encode_vhost(vhost_name)
        encoded_queue = urllib.parse.quote(queue_name, safe="")
        data = {
            "durable": durable,
            "auto_delete": auto_delete,
            "arguments": arguments or {},
        }
        response = self._request(
            "PUT",
            f"queues/{encoded_vhost}/{encoded_queue}",
            data=data,
        )
        if response.status_code in (201, 204):
            print(f"  [OK] Queue '{queue_name}' created on vhost '{vhost_name}'")
            return True
        else:
            print(f"  [FAIL] Failed to create queue: "
                  f"{response.status_code} - {response.text}")
            return False

    def create_binding(
        self,
        vhost_name: str,
        exchange_name: str,
        queue_name: str,
        routing_key: str = "",
        arguments: Optional[dict] = None,
    ) -> bool:
        """Create a binding between an exchange and a queue."""
        encoded_vhost = self._encode_vhost(vhost_name)
        encoded_exchange = urllib.parse.quote(exchange_name, safe="")
        encoded_queue = urllib.parse.quote(queue_name, safe="")
        data = {
            "routing_key": routing_key,
            "arguments": arguments or {},
        }
        response = self._request(
            "POST",
            f"bindings/{encoded_vhost}/e/{encoded_exchange}/q/{encoded_queue}",
            data=data,
        )
        if response.status_code in (201, 204):
            print(f"  [OK] Binding created: '{exchange_name}' -> '{queue_name}' "
                  f"(routing_key: '{routing_key}')")
